return-response.set-body:
@{
        var requestBody = context.Request.Body.As(preserveContent: true);
        var messages = requestBody?["messages"] as JArray;
        var lastMessage = messages?.Last?["content"]?.ToString() ?? "Hello";

        var responseId = "chatcmpl-stub-" + context.RequestId.ToString().Substring(0, 8);
        var timestamp = (int)(DateTime.UtcNow - new DateTime(1970, 1, 1)).TotalSeconds;

        return new JObject(
          new JProperty("id", responseId),
          new JProperty("object", "chat.completion"),
          new JProperty("created", timestamp),
          new JProperty("model", "gpt-4o-stub"),
          new JProperty("choices", new JArray(
            new JObject(
              new JProperty("index", 0),
              new JProperty("message", new JObject(
                new JProperty("role", "assistant"),
                new JProperty("content", "[STUB] This is a mock response from the Foundry API stub. Your message was: " + lastMessage + ". To get real AI responses, configure a real Azure AI Foundry endpoint. See the README for upgrade instructions.")
              )),
              new JProperty("finish_reason", "stop")
            )
          )),
          new JProperty("usage", new JObject(
            new JProperty("prompt_tokens", 10),
            new JProperty("completion_tokens", 42),
            new JProperty("total_tokens", 52)
          ))
        ).ToString();
      }
